@ClientEndpoint
public class WebSocketService {
    private final PocModel model;
    private Session session;
    private final ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor();

    public WebSocketService(PocModel model) { this.model = model; }

    public void connect(URI uri) throws DeploymentException, IOException {
        ContainerProvider.getWebSocketContainer().connectToServer(this, uri);
    }

    @OnOpen
    public void onOpen(Session session) {
        this.session = session;
        log.info("WebSocket connected: {}", session.getId());
    }

    @OnMessage
    public void onMessage(String json) {
        SwingUtilities.invokeLater(() -> {
            CustomerPayload payload = CustomerPayloadParser.parse(json);
            model.setValue(ModelProperties.FIRST_NAME, payload.getFirst());
            model.setValue(ModelProperties.LAST_NAME, payload.getName());
            model.setValue(ModelProperties.IBAN, payload.getIban());
            // ... all fields
        });
    }

    @OnClose
    public void onClose(Session session, CloseReason reason) {
        log.warn("WebSocket closed: {} — reconnecting", reason.getReasonPhrase());
        scheduler.schedule(() -> connect(uri), 2, TimeUnit.SECONDS);
    }
}

