            if (button.isSelected())
                model.setValue(ModelProperties.GENDER, gender);
        }));
}

public class HttpBinService {
    private final HttpClient client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(5))
        .build();

    public CompletableFuture<String> postAsync(Map<String, String> data) {
        String json = buildJson(data);
        var request = HttpRequest.newBuilder()
            .uri(URI.create(ApplicationConfig.getHttpEndpoint() + "/post"))
            .header("Content-Type", "application/json")
            .POST(HttpRequest.BodyPublishers.ofString(json))
            .timeout(Duration.ofSeconds(10))
            .build();
        return client.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(response -> {
                if (response.statusCode() < 200 || response.statusCode() >= 300)
                    throw new CompletionException(new IOException("HTTP " + response.statusCode()));
                return response.body();
            });
    }
}

connect(retryDelayMs = 1000) {
    this.socket = new WebSocket(process.env.VUE_APP_WS_URL);
    this.socket.onopen = () => {
        this.connected = true;
        console.log('WebSocket connected');
    };
    this.socket.onclose = () => {
        this.connected = false;
        if (retryDelayMs <= 32000) {
            console.log(`Reconnecting in ${retryDelayMs}ms...`);
            setTimeout(() => this.connect(retryDelayMs * 2), retryDelayMs);
        } else {
            console.warn('Max reconnection attempts reached');
        }
    };
    this.socket.onerror = () => this.socket.close();
},

// Java: PocModel.java
public ValidationResult validate() {
    var errors = new ArrayList<String>();
    var firstName = getStringValue(ModelProperties.FIRST_NAME);
    var lastName  = getStringValue(ModelProperties.LAST_NAME);
    var iban      = getStringValue(ModelProperties.IBAN);
    var plz       = getStringValue(ModelProperties.ZIP);
    if (firstName == null || firstName.isBlank())
        errors.add("Vorname ist erforderlich");
    if (lastName == null || lastName.isBlank())
        errors.add("Nachname ist erforderlich");
    if (iban != null && !IbanValidator.isValid(iban))
        errors.add("IBAN-Format ist ungültig");
    if (plz != null && !plz.matches("\\d{5}"))
        errors.add("PLZ muss 5 Ziffern haben");
    return new ValidationResult(errors);
}

